import asyncio
import json
import uuid
from typing import Dict, List
from websockets import serve, ConnectionClosed

class Player:
    def __init__(self, name):
        self.name = name
        self.inventory = {}

class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.lock = asyncio.Lock()

    async def handle_connection(self, websocket, path):
        try:
            while True:
                data = await websocket.recv()
                if not data:
                    break
                message = json.loads(data)
                action = message['action']
                player_name = message['player_name']

                if action == 'login':
                    self.players[player_name] = Player(player_name)

                elif action == 'add_item':
                    item_id = message['item_id']
                    quantity = message['quantity']
                    await self.add_item_to_player(player_name, item_id, quantity)

                elif action == 'remove_item':
                    item_id = message['item_id']
                    quantity = message['quantity']
                    await self.remove_item_from_player(player_name, item_id, quantity)

                elif action == 'trade':
                    player_name_other = message['player_name_other']
                    item_id = message['item_id']
                    quantity = message['quantity']
                    await self.trade_items(player_name, player_name_other, item_id, quantity)

        except ConnectionClosed:
            pass

    async def add_item_to_player(self, player_name: str, item_id: str, quantity: int):
        async with self.lock:
            if player_name in self.players:
                if item_id not in self.players[player_name].inventory:
                    self.players[player_name].inventory[item_id] = 0
                self.players[player_name].inventory[item_id] += quantity

    async def remove_item_from_player(self, player_name: str, item_id: str, quantity: int):
        async with self.lock:
            if player_name in self.players and item_id in self.players[player_name].inventory:
                if self.players[player_name].inventory[item_id] >= quantity:
                    self.players[player_name].inventory[item_id] -= quantity
                else:
                    raise ValueError("Insufficient quantity")

    async def trade_items(self, player_name: str, player_name_other: str, item_id: str, quantity: int):
        async with self.lock:
            if player_name in self.players and player_name_other in self.players:
                await self.remove_item_from_player(player_name, item_id, quantity)
                await self.add_item_to_player(player_name_other, item_id, quantity)

    async def start(self):
        async with serve(self.handle_connection, "localhost", 8765):
            await asyncio.Future()  # run forever

if __name__ == "__main__":
    game_server = GameServer()
    asyncio.run(game_server.start())